// Parse and validate body
const body = $input.first().json.body || $input.first().json;

// UUID regex pattern
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!body.tenantId || !uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid or missing tenantId');
}

return [{ json: {
  tenantId: body.tenantId,
  periodeDebut: body.periodeDebut,
  periodeFin: body.periodeFin,
  type: body.type
} }];

// Aggregate transactions by TVA rate
const transactions = $input.all()[0].json;
const aggregated = {};
let totalHT = 0, totalTVA = 0, totalTTC = 0, count = 0;

if (Array.isArray(transactions)) {
  transactions.forEach(t => {
    const rate = t.taux_tva || 'standard';
    if (!aggregated[rate]) aggregated[rate] = { ht: 0, tva: 0, ttc: 0, count: 0 };
    aggregated[rate].ht += parseFloat(t.montant_ht || 0);
    aggregated[rate].tva += parseFloat(t.montant_tva || 0);
    aggregated[rate].ttc += parseFloat(t.montant_ttc || 0);
    aggregated[rate].count += 1;
    totalHT += parseFloat(t.montant_ht || 0);
    totalTVA += parseFloat(t.montant_tva || 0);
    totalTTC += parseFloat(t.montant_ttc || 0);
    count += 1;
  });
}

return {
  transactions: aggregated,
  totalHT: totalHT,
  totalTVA: totalTVA,
  totalTTC: totalTTC,
  count: count
};

return {
  success: true,
  message: 'E-reporting generated successfully',
  data: $input.all()[0].json
};
